def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(pos1 - pos2) / speed

    def is_within_time_window(visit_time, time_window):
        return time_window[0] <= visit_time <= time_window[1]

    best_node = None
    min_time_penalty = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        projected_arrival_time = current_time + travel_time
        window = time_windows[idx]
        if is_within_time_window(projected_arrival_time, window):
            time_penalty = window[1] - projected_arrival_time
        else:
            time_penalty = (projected_arrival_time - window[1]) ** 2  # Penalty is squared for arriving late

        if time_penalty < min_time_penalty:
            min_time_penalty = time_penalty
            best_node = idx

    # If no best node found within time windows, opt to return to depot and wait
    if best_node is None:
        depot_travel_time = calculate_travel_time(cur_truck_pos, depot_pos, truck_speed)
        depot_arrival_time = current_time + depot_travel_time
        # Check if waiting at the depot makes sense compared to waiting at the current location
        if depot_arrival_time < min(time_window[0] for time_window in time_windows):
            return None  # Instructs to wait if going to depot isn't beneficial
        else:
            best_node = unvisited_customers.index(depot_pos)

    return best_node

