def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(start, end):
        return np.linalg.norm(end - start) / truck_speed

    priority_queue = []

    for idx, customer in enumerate(unvisited_customers):
        time_to_customer = travel_time(cur_truck_pos, customer)
        window_start, window_end = time_windows[idx]

        if current_time + time_to_customer <= window_end:
            urgency = window_end - (current_time + time_to_customer)
            heapq.heappush(priority_queue, (urgency, idx))

    if priority_queue:
        best_node = heapq.heappop(priority_queue)[1]
    else:
        best_node = None

    return best_node

