def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    if not unvisited_customers:
        return None  # No places to go

    best_node = None
    lowest_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time_to_customer = distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time_to_customer

        start_time_window, end_time_window = time_windows[i]
        window_midpoint = (start_time_window + end_time_window) / 2

        if arrival_time > end_time_window:
            penalty = (arrival_time - end_time_window)
        elif arrival_time < start_time_window:
            penalty = (start_time_window - arrival_time)
        else:
            penalty = 0

        # Heuristic cost calculation
        urgency_factor = np.abs(arrival_time - window_midpoint)
        cost = travel_time_to_customer + penalty * 2 + urgency_factor

        if cost < lowest_cost:
            lowest_cost = cost
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(start, end):
        distance = np.linalg.norm(start - end)
        return distance / truck_speed

    time_until_window_closes = [max(0, tw[1] - current_time) for tw in time_windows]
    travel_times = [calculate_travel_time(cur_truck_pos, customer) for customer in unvisited_customers]

    urgency_scores = [(time_until_window_closes[i] - travel_times[i])
                      if time_until_window_closes[i] >= travel_times[i] else float('inf')
                      for i in range(len(unvisited_customers))]

    best_node = None

    if min(urgency_scores) == float('inf'):
        # If all unvisited have inf scores, it means no feasible visit without penalty
        if time_until_window_closes and min(time_until_window_closes) > 0:
            best_node = np.argmin(time_until_window_closes)
        else:
            best_node = None  # instruct truck to wait if everything is inf and all time windows are past
    else:
        # Choose the node with the highest urgency requiring immediate move
        best_node = np.argmin(urgency_scores)

    return best_node
